#include <stdio.h>
#include <stdbool.h>

static bool hasDistinct(int *a, int n, int y) {
    int first = a[0] | y;
    for (int i = 1; i < n; ++i) {
        if ((a[i] | y) != first) return true;
    }
    return false;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        int a[N];
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int lo = 0, hi = X, ans = 0;
        while (lo <= hi) {
            int mid = lo + ((hi - lo) >> 1);
            if (hasDistinct(a, N, mid)) {
                ans = mid; // mid works, try higher
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

