bool hasDistinct(const vector<int>& a, int y) {
    int first = a[0] | y;
    for (size_t i = 1; i < a.size(); ++i) {
        if ((a[i] | y) != first) return true;
    }
    return false;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N, X; cin >> N >> X;
        vector<int> a(N);
        for (int &v : a) cin >> v;
        int lo = 0, hi = X, ans = 0;
        while (lo <= hi) {
            int mid = lo + ((hi - lo) >> 1);
            if (hasDistinct(a, mid)) {
                ans = mid;
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        cout << ans << '\n';
    }
    return 0;
}

