import sys

def has_distinct(arr, y):
    first = arr[0] | y
    for v in arr[1:]:
        if (v | y) != first:
            return True
    return False

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); x = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        lo, hi, ans = 0, x, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if has_distinct(a, mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

